from pathlib import Path
import json


def _has_addr(email: dict, addr: str) -> bool:
    """Check if addr appears in any recipient field of the email."""
    for field in ("to_addr", "cc_addr", "bcc_addr"):
        val = email.get(field) or ""
        if addr.lower() in val.lower():
            return True
    return False


def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check mailbox.json"}

    mailbox_path = Path(external_services_path) / "mailbox.json"
    if not mailbox_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "mailbox.json not found at external_services_path"}

    with open(mailbox_path, "r") as f:
        data = json.load(f)

    emails = data.get("emails", [])
    sent   = [e for e in emails if e.get("folder", "").lower() == "sent"]
    inbox  = [e for e in emails if e.get("folder", "").lower() == "inbox"]
    drafts = [e for e in emails if e.get("folder", "").lower() == "drafts"]
    trash  = [e for e in emails if e.get("folder", "").lower() == "trash"]

    issues = []

    # --- Fixed folder counts ---
    if len(inbox) != 6:
        issues.append(f"INBOX has {len(inbox)} emails, expected 6")
    if len(drafts) != 0:
        issues.append(f"Drafts has {len(drafts)} emails, expected 0")
    if len(trash) != 0:
        issues.append(f"Trash has {len(trash)} emails, expected 0")

    # --- Required sent emails ---
    # 1. Vasquez consent form
    vasquez_consent = [
        e for e in sent
        if "evasquez79@gmail.com" in (e.get("to_addr") or "").lower()
        and "consent form required" in (e.get("subject") or "").lower()
        and "vasquez" in (e.get("subject") or "").lower()
    ]
    if not vasquez_consent:
        issues.append(
            "No sent email to evasquez79@gmail.com with subject matching "
            "'Consent Form Required | Vasquez'"
        )

    # 2. Thompson incomplete referral
    thompson_referral = [
        e for e in sent
        if "abriggs@buffaloheme.com" in (e.get("to_addr") or "").lower()
        and "incomplete referral" in (e.get("subject") or "").lower()
        and "thompson" in (e.get("subject") or "").lower()
    ]
    if not thompson_referral:
        issues.append(
            "No sent email to abriggs@buffaloheme.com with subject matching "
            "'Incomplete Referral | Thompson'"
        )

    # 3. Legal forward — both recipients must appear somewhere across sent emails
    #    Acceptable as one email (both in to/cc) or two separate emails
    legal_reached   = any(_has_addr(e, "legal@careig.com")   for e in sent)
    lmurphy_reached = any(_has_addr(e, "lmurphy@careig.com") for e in sent)
    if not legal_reached:
        issues.append(
            "legal@careig.com not found as a recipient in any sent email "
            "(email_id 7 forward required per SOP §12.1)"
        )
    if not lmurphy_reached:
        issues.append(
            "lmurphy@careig.com not found as a recipient in any sent email "
            "(email_id 7 forward required per SOP §12.1)"
        )

    # --- Sent count: 4 (one forward) or 5 (two separate forwards) ---
    if len(sent) not in (4, 5):
        issues.append(f"Sent folder has {len(sent)} emails, expected 4 or 5")

    if issues:
        return {"pass": False, "score": 0.0, "feedback": "; ".join(issues)}

    return {
        "pass": True,
        "score": 1.0,
        "feedback": (
            f"Folder counts correct: Sent={len(sent)}, INBOX={len(inbox)}, "
            f"Drafts={len(drafts)}, Trash={len(trash)}. "
            "All required sent emails present."
        ),
    }

