def _is_forward_of(email: dict, msg_id: str) -> bool:
    """True if sent email is a forward: in_reply_to matches msg_id, or subject has Fwd:/FW:."""
    in_reply_to = email.get("in_reply_to") or ""
    if msg_id and msg_id in in_reply_to:
        return True
    subject = email.get("subject") or ""
    return bool(re.search(r"\b(fwd?:|fw:)", subject, re.IGNORECASE))


