    return text.strip().lower()


def _val_str(v) -> str:
    if v is None:
        return ""
    if isinstance(v, datetime.datetime):
        return _normalize(v.strftime("%Y-%m-%d %I:%M %p"))
    if isinstance(v, datetime.date):
        return _normalize(str(v))
    return _normalize(str(v))


