        wb = openpyxl.load_workbook(str(target_file), data_only=True)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Could not open '{target_file.name}': {e}"}

    # The rubric says: exactly 3 data rows starting at row 6
    # This means rows 1-5 are header/metadata, and data rows are 6, 7, 8
    # We check that row 6, 7, 8 have data and row 9 does not (or doesn't exist)

    for sheet_name in wb.sheetnames:
        ws = wb[sheet_name]

