        max_row_to_check = ws.max_row if ws.max_row else 20

        for row_num in range(data_row_start, max_row_to_check + 1):
            row_cells = [ws.cell(row=row_num, column=col).value for col in range(1, (ws.max_column or 10) + 1)]
            has_data = any(cell is not None and str(cell).strip() != '' for cell in row_cells)
            if has_data:
                data_row_count += 1
            # Don't break on empty row in case there are gaps, but typically data is contiguous

        if data_row_count == 3:
            return {
                "pass": True,
                "score": 1.0,
                "feedback": f"Found exactly 3 data rows starting from row 6 in sheet '{sheet_name}' of '{target_file.name}'. Data rows span rows {data_row_start} to {data_row_start + 2}. Total data rows counted: {data_row_count}."
            }
        else:
            # Check if another sheet might match
            continue

    # If we get here, no sheet matched
    # Provide detailed feedback about what we found
    feedback_parts = []
    for sheet_name in wb.sheetnames:
        ws = wb[sheet_name]
